export declare const CREATE_SESSIONS_TABLE = "\n  CREATE TABLE IF NOT EXISTS sessions (\n    id TEXT PRIMARY KEY,\n    started_at TEXT NOT NULL,\n    ended_at TEXT,\n    working_directory TEXT,\n    config_hash TEXT,\n    metadata TEXT  -- JSON\n  );\n";
export declare const CREATE_TURNS_TABLE = "\n  CREATE TABLE IF NOT EXISTS turns (\n    id TEXT PRIMARY KEY,\n    session_id TEXT NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,\n    turn_num INTEGER NOT NULL,\n    prompt_text TEXT,\n    timestamp TEXT NOT NULL,\n    action_count INTEGER NOT NULL DEFAULT 0,\n    UNIQUE(session_id, turn_num)\n  );\n";
export declare const CREATE_ACTIONS_TABLE = "\n  CREATE TABLE IF NOT EXISTS actions (\n    id TEXT PRIMARY KEY,\n    session_id TEXT NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,\n    turn_id TEXT REFERENCES turns(id) ON DELETE SET NULL,\n    sequence_num INTEGER NOT NULL,\n    timestamp TEXT NOT NULL,\n    action_type TEXT NOT NULL,  -- 'mcp_call', 'file_change', 'checkpoint'\n    tool_name TEXT,\n    namespace TEXT,\n    parameters TEXT,  -- JSON\n    result_success INTEGER,\n    result_data TEXT,  -- JSON\n    result_latency_ms INTEGER,\n    pre_hash TEXT,\n    post_hash TEXT,\n    reversibility_class TEXT,  -- 'A', 'B', 'C', 'D'\n    inverse_tool TEXT,\n    inverse_params TEXT,  -- JSON\n    inverse_source TEXT,  -- 'explicit_contract', 'filesystem_shadow', 'heuristic', 'llm_suggestion'\n    inverse_confidence REAL,\n    pre_snapshot_id TEXT,\n    post_snapshot_id TEXT,\n    state TEXT NOT NULL DEFAULT 'executed',  -- 'executed', 'undone', 'undo_failed'\n    undone_at TEXT,\n    undo_result TEXT,  -- JSON\n    undo_error TEXT,\n    metadata TEXT,  -- JSON\n    UNIQUE(session_id, sequence_num)\n  );\n";
export declare const CREATE_INDEXES: string[];
export declare const MIGRATIONS: string[];
